%% P5_Exp07_LFP_MarketScale_Extension.m
% Purpose:
% This script extends the Part5 Exp01 LFP optimization to
% exploratory market-throughput scenarios from 5,000 to 500,000 tons.
%
% It does not rerun the residual model or threshold-grid search. Instead, it
% reuses the k-dependent per-pack decision losses, thresholds, action
% allocations, and executed pathway values already generated by Part5
% Exp01. This guarantees that the market-scale extension uses exactly the
% same residual realization and economic assumptions as the manuscript
% scale analysis.

clear;
clc;
close all;

format compact;
format shortG;

%% 0) Path configuration
cfg = struct();

script_dir = fileparts(mfilename('fullpath'));

if isempty(script_dir)
 script_dir = pwd;
end

cfg.output_dir = fullfile(script_dir, 'Output');
cfg.results_dir = fullfile(cfg.output_dir, 'Results');

cfg.lfp_result_primary = fullfile(cfg.results_dir, ...
 'P5_Exp01_ScaleDependent_LFP_Results.mat');

cfg.lfp_result_legacy = fullfile(cfg.output_dir, ...
 'Result01_ScaleEffect_LFP_Results.mat');

cfg.market_scale_csv = fullfile(cfg.results_dir, ...
 'P5_Exp07_LFP_MarketScale_Extension_Table.csv');

cfg.cost_breakdown_csv = fullfile(cfg.results_dir, ...
 'P5_Exp07_LFP_MarketScale_CostBreakdown.csv');

cfg.market_only_csv = fullfile(cfg.results_dir, ...
 'P5_Exp07_LFP_MarketScale_OnlyRows.csv');

cfg.result_mat = fullfile(cfg.results_dir, ...
 'P5_Exp07_LFP_MarketScale_Extension_Results.mat');

% Exploratory market-throughput scenarios.
cfg.scale_ton_list = [ ...
 5000; 10000; 20000; 50000; ...
 100000; 200000; 300000; 500000];

% LFP pack mass used in Part5 Exp01.
cfg.M_pack_kg = 173.25;

cfg.accounting_tolerance_abs_USD = 1e-5;
cfg.accounting_tolerance_rel = 1e-10;

if ~exist(cfg.results_dir, 'dir')
 mkdir(cfg.results_dir);
end

if isfile(cfg.lfp_result_primary)
 cfg.input_file = cfg.lfp_result_primary;
elseif isfile(cfg.lfp_result_legacy)
 cfg.input_file = cfg.lfp_result_legacy;
else
 error(['Part5 Exp01 LFP result was not found.\nChecked:\n%s\n%s\n' ...
 'Run the Part5 Exp01 before running Exp07.'], ...
 cfg.lfp_result_primary, cfg.lfp_result_legacy);
end

fprintf('================ Part5 Exp07 LFP market-scale extension ================\n');
fprintf('Input Part5 Exp01 result: %s\n', cfg.input_file);
fprintf('Market-scale table: %s\n', cfg.market_scale_csv);
fprintf('Cost-breakdown table: %s\n', cfg.cost_breakdown_csv);
fprintf('Result MAT: %s\n', cfg.result_mat);

%% 1) Load the Part5 Exp01 result
S = load(cfg.input_file);
R = S;

field_names = fieldnames(S);

for ii = 1:numel(field_names)

 field_now = field_names{ii};

 if isstruct(S.(field_now)) && ...
 isfield(S.(field_now), 'k_vals') && ...
 isfield(S.(field_now), 'O_base')

 R = S.(field_now);
 fprintf('Using result structure: %s\n', field_now);
 break;
 end
end

required_fields = { ...
 'k_vals', ...
 'O_base', ...
 'A_base', ...
 'R_base', ...
 'T1_base', ...
 'T2_base', ...
 'Pred_Action_Ratio_byK', ...
 'A1_value_perpack_byK', ...
 'A2_value_perpack_byK', ...
 'A3_value_perpack_byK', ...
 'Model_Cost_NK'};

for ii = 1:numel(required_fields)
 field_now = required_fields{ii};

 if ~isfield(R, field_now)
 error('Required Part5 Exp01 field is missing: %s', field_now);
 end
end

k_vals = double(R.k_vals(:));
O_base = double(R.O_base(:));
A_base = double(R.A_base(:));
R_base = double(R.R_base(:));

T1_base = double(R.T1_base(:));
T2_base = double(R.T2_base(:));

Pred_Action_Ratio_byK = double(R.Pred_Action_Ratio_byK);
A1_value_perpack_byK = double(R.A1_value_perpack_byK(:));
A2_value_perpack_byK = double(R.A2_value_perpack_byK(:));
A3_value_perpack_byK = double(R.A3_value_perpack_byK(:));

Model_Cost_NK_upstream = double(R.Model_Cost_NK);

num_k = numel(k_vals);

expected_lengths = [ ...
 numel(O_base), ...
 numel(A_base), ...
 numel(R_base), ...
 numel(T1_base), ...
 numel(T2_base), ...
 numel(A1_value_perpack_byK), ...
 numel(A2_value_perpack_byK), ...
 numel(A3_value_perpack_byK)];

if any(expected_lengths ~= num_k)
 error('The k-dependent Part5 Exp01 arrays have inconsistent lengths.');
end

if ~isequal(size(Pred_Action_Ratio_byK), [num_k, 3])
 error('Pred_Action_Ratio_byK must have size [num_k, 3].');
end

if any(~isfinite(k_vals)) || any(diff(k_vals) <= 0)
 error('k_vals must be finite and strictly increasing.');
end

if any([O_base; A_base; R_base] < -1e-10)
 error('Per-pack decision-cost components must be non-negative.');
end

% Recover the upstream information-cost equation from Model_Cost_NK.
if size(Model_Cost_NK_upstream, 2) == num_k
 model_cost_by_k = Model_Cost_NK_upstream(1, :).';
elseif size(Model_Cost_NK_upstream, 1) == num_k
 model_cost_by_k = Model_Cost_NK_upstream(:, 1);
else
 error('Model_Cost_NK has an unexpected shape.');
end

if num_k < 2
 error('At least two k values are required to recover information cost.');
end

c_pack = median(diff(model_cost_by_k) ./ diff(k_vals));
c_train_by_k = model_cost_by_k - k_vals .* c_pack;
c_train = median(c_train_by_k);

model_cost_reconstruction_error = max(abs( ...
 model_cost_by_k - (k_vals .* c_pack + c_train)));

if model_cost_reconstruction_error > 1e-6
 error(['The upstream information-cost curve is not linear in k. ' ...
 'Inspect Model_Cost_NK before extending the market scale.']);
end

fprintf('>>> Loaded k range: %d to %d\n', min(k_vals), max(k_vals));
fprintf('>>> Recovered c_pack = %.4f USD and c_train = %.4f USD\n', ...
 c_pack, c_train);

%% 2) Construct market-scale cost matrices
scale_ton_list = double(cfg.scale_ton_list(:));
N_list = max(1, round(scale_ton_list .* 1000 ./ cfg.M_pack_kg));

num_N = numel(N_list);

O_Cost_NK = N_list .* O_base.';
A_Cost_NK = N_list .* A_base.';
R_Cost_NK = N_list .* R_base.';

Model_Cost_NK = repmat( ...
 (k_vals .* c_pack + c_train).', ...
 num_N, 1);

Total_Cost_NK = ...
 O_Cost_NK + ...
 A_Cost_NK + ...
 R_Cost_NK + ...
 Model_Cost_NK;

[opt_total_cost_of_N, opt_idx_of_N] = min(Total_Cost_NK, [], 2);

opt_k_of_N = k_vals(opt_idx_of_N);
opt_T1_of_N = T1_base(opt_idx_of_N);
opt_T2_of_N = T2_base(opt_idx_of_N);

row_idx = (1:num_N).';

opt_O_of_N = O_Cost_NK(sub2ind( ...
 size(O_Cost_NK), row_idx, opt_idx_of_N));

opt_A_of_N = A_Cost_NK(sub2ind( ...
 size(A_Cost_NK), row_idx, opt_idx_of_N));

opt_R_of_N = R_Cost_NK(sub2ind( ...
 size(R_Cost_NK), row_idx, opt_idx_of_N));

opt_Model_of_N = Model_Cost_NK(sub2ind( ...
 size(Model_Cost_NK), row_idx, opt_idx_of_N));

opt_Action_Ratio_of_N = Pred_Action_Ratio_byK(opt_idx_of_N, :);

opt_A1_value_of_N = ...
 N_list .* A1_value_perpack_byK(opt_idx_of_N);

opt_A2_value_of_N = ...
 N_list .* A2_value_perpack_byK(opt_idx_of_N);

opt_A3_value_of_N = ...
 N_list .* A3_value_perpack_byK(opt_idx_of_N);

opt_cost_per_pack_of_N = ...
 opt_total_cost_of_N ./ N_list;

%% 3) Compute gross and net realized pathway value
% The action-value components are already evaluated under the executed
% predicted action. Therefore, opportunity loss must not be subtracted a
% second time from the executed pathway value.

Gross_executed_action_value_of_N = ...
 opt_A1_value_of_N + ...
 opt_A2_value_of_N + ...
 opt_A3_value_of_N;

Net_realized_value_of_N = ...
 Gross_executed_action_value_of_N ...
 - opt_A_of_N ...
 - opt_R_of_N ...
 - opt_Model_of_N;

% Equivalent perfect-information accounting.
gross_executed_per_pack_by_k = ...
 A1_value_perpack_byK + ...
 A2_value_perpack_byK + ...
 A3_value_perpack_byK;

oracle_value_per_pack_by_k = ...
 gross_executed_per_pack_by_k + O_base;

oracle_value_spread = ...
 max(oracle_value_per_pack_by_k) - ...
 min(oracle_value_per_pack_by_k);

if oracle_value_spread > 1e-6
 warning(['The reconstructed perfect-information value varies slightly ' ...
 'across k by %.6g USD per pack. This should be Monte Carlo ' ...
 'round-off only.'], oracle_value_spread);
end

Perfect_information_action_value_of_N = ...
 N_list .* oracle_value_per_pack_by_k(opt_idx_of_N);

Net_realized_value_oracle_form = ...
 Perfect_information_action_value_of_N ...
 - opt_O_of_N ...
 - opt_A_of_N ...
 - opt_R_of_N ...
 - opt_Model_of_N;

Net_value_accounting_error_USD = ...
 Net_realized_value_of_N - ...
 Net_realized_value_oracle_form;

net_value_tolerance_USD = max( ...
 cfg.accounting_tolerance_abs_USD, ...
 cfg.accounting_tolerance_rel .* ...
 max(max(abs(Net_realized_value_of_N)), 1));

if max(abs(Net_value_accounting_error_USD)) > net_value_tolerance_USD
 error(['Executed-value and perfect-information net-value accounting ' ...
 'are inconsistent. Maximum discrepancy = %.6g USD.'], ...
 max(abs(Net_value_accounting_error_USD)));
end

%% 4) Boundary diagnostics
Is_k_on_lower_boundary = opt_k_of_N == min(k_vals);
Is_k_on_upper_boundary = opt_k_of_N == max(k_vals);

if any(Is_k_on_upper_boundary)
 warning(['At least one market-scale scenario selects k* = max(k_vals) ' ...
 '= %d. The reported optimum may be truncated by the current ' ...
 'residual-extrapolation range.'], max(k_vals));
end

Label_density_per_ton = ...
 opt_k_of_N ./ scale_ton_list;

%% 5) Build output tables
Opportunity_loss_total_USD = opt_O_of_N;
Handling_rework_total_USD = opt_A_of_N;
Risk_penalty_total_USD = opt_R_of_N;
Information_cost_total_USD = opt_Model_of_N;

Decision_cost_total_USD = ...
 Opportunity_loss_total_USD + ...
 Handling_rework_total_USD + ...
 Risk_penalty_total_USD;

Opportunity_loss_per_pack_USD = ...
 Opportunity_loss_total_USD ./ N_list;

Handling_rework_per_pack_USD = ...
 Handling_rework_total_USD ./ N_list;

Risk_penalty_per_pack_USD = ...
 Risk_penalty_total_USD ./ N_list;

Information_cost_per_pack_USD = ...
 Information_cost_total_USD ./ N_list;

Decision_cost_per_pack_USD = ...
 Decision_cost_total_USD ./ N_list;

Opportunity_loss_share_percent = ...
 100 .* Opportunity_loss_total_USD ./ opt_total_cost_of_N;

Handling_rework_share_percent = ...
 100 .* Handling_rework_total_USD ./ opt_total_cost_of_N;

Risk_penalty_share_percent = ...
 100 .* Risk_penalty_total_USD ./ opt_total_cost_of_N;

Information_cost_share_percent = ...
 100 .* Information_cost_total_USD ./ opt_total_cost_of_N;

Decision_cost_share_percent = ...
 100 .* Decision_cost_total_USD ./ opt_total_cost_of_N;

MarketScale_Table = table( ...
 scale_ton_list, ...
 N_list, ...
 opt_k_of_N, ...
 Is_k_on_lower_boundary, ...
 Is_k_on_upper_boundary, ...
 Label_density_per_ton, ...
 opt_T1_of_N, ...
 opt_T2_of_N, ...
 opt_total_cost_of_N, ...
 opt_cost_per_pack_of_N, ...
 Opportunity_loss_total_USD, ...
 Handling_rework_total_USD, ...
 Risk_penalty_total_USD, ...
 Information_cost_total_USD, ...
 Decision_cost_total_USD, ...
 Opportunity_loss_per_pack_USD, ...
 Handling_rework_per_pack_USD, ...
 Risk_penalty_per_pack_USD, ...
 Information_cost_per_pack_USD, ...
 Decision_cost_per_pack_USD, ...
 Opportunity_loss_share_percent, ...
 Handling_rework_share_percent, ...
 Risk_penalty_share_percent, ...
 Information_cost_share_percent, ...
 Decision_cost_share_percent, ...
 opt_Action_Ratio_of_N(:, 1), ...
 opt_Action_Ratio_of_N(:, 2), ...
 opt_Action_Ratio_of_N(:, 3), ...
 opt_A1_value_of_N, ...
 opt_A2_value_of_N, ...
 opt_A3_value_of_N, ...
 Gross_executed_action_value_of_N, ...
 Perfect_information_action_value_of_N, ...
 Net_realized_value_of_N, ...
 Net_value_accounting_error_USD, ...
 Gross_executed_action_value_of_N ./ 1e9, ...
 Net_realized_value_of_N ./ 1e9, ...
 'VariableNames', { ...
 'Scale_ton', ...
 'Pack_number', ...
 'Optimal_k', ...
 'Is_k_on_lower_boundary', ...
 'Is_k_on_upper_boundary', ...
 'Label_density_per_ton', ...
 'T1_star', ...
 'T2_star', ...
 'Total_recertification_cost_USD', ...
 'Total_recertification_cost_per_pack_USD', ...
 'Opportunity_loss_USD', ...
 'Mismatch_handling_rework_cost_USD', ...
 'Risk_penalty_USD', ...
 'SOH_labelling_adaptation_cost_USD', ...
 'Decision_cost_USD', ...
 'Opportunity_loss_per_pack_USD', ...
 'Mismatch_handling_rework_cost_per_pack_USD', ...
 'Risk_penalty_per_pack_USD', ...
 'SOH_labelling_adaptation_cost_per_pack_USD', ...
 'Decision_cost_per_pack_USD', ...
 'Opportunity_loss_share_percent', ...
 'Mismatch_handling_rework_cost_share_percent', ...
 'Risk_penalty_share_percent', ...
 'SOH_labelling_adaptation_cost_share_percent', ...
 'Decision_cost_share_percent', ...
 'A1_direct_reuse_share', ...
 'A2_refurbishment_share', ...
 'A3_recycling_share', ...
 'A1_direct_reuse_value_USD', ...
 'A2_refurbishment_value_USD', ...
 'A3_recycling_value_USD', ...
 'Gross_executed_action_value_USD', ...
 'Perfect_information_action_value_USD', ...
 'Net_realized_value_USD', ...
 'Net_value_accounting_error_USD', ...
 'Gross_executed_action_value_billion_USD', ...
 'Net_realized_value_billion_USD'});

CostBreakdown_Table = table( ...
 scale_ton_list, ...
 N_list, ...
 opt_k_of_N, ...
 Is_k_on_upper_boundary, ...
 opt_T1_of_N, ...
 opt_T2_of_N, ...
 opt_total_cost_of_N ./ 1e6, ...
 Opportunity_loss_total_USD ./ 1e6, ...
 Handling_rework_total_USD ./ 1e6, ...
 Risk_penalty_total_USD ./ 1e6, ...
 Information_cost_total_USD ./ 1e6, ...
 Decision_cost_total_USD ./ 1e6, ...
 opt_cost_per_pack_of_N, ...
 Opportunity_loss_per_pack_USD, ...
 Handling_rework_per_pack_USD, ...
 Risk_penalty_per_pack_USD, ...
 Information_cost_per_pack_USD, ...
 Decision_cost_per_pack_USD, ...
 'VariableNames', { ...
 'Scale_ton', ...
 'Pack_number', ...
 'Optimal_k', ...
 'Is_k_on_upper_boundary', ...
 'T1_star', ...
 'T2_star', ...
 'Total_cost_MUSD', ...
 'Opportunity_loss_MUSD', ...
 'Mismatch_handling_rework_cost_MUSD', ...
 'Risk_penalty_MUSD', ...
 'SOH_labelling_adaptation_cost_MUSD', ...
 'Decision_cost_MUSD', ...
 'Total_cost_per_pack_USD', ...
 'Opportunity_loss_per_pack_USD', ...
 'Mismatch_handling_rework_cost_per_pack_USD', ...
 'Risk_penalty_per_pack_USD', ...
 'SOH_labelling_adaptation_cost_per_pack_USD', ...
 'Decision_cost_per_pack_USD'});

MarketScale_Only_Table = MarketScale_Table;
CostBreakdown_Only_Table = CostBreakdown_Table;

writetable(MarketScale_Table, cfg.market_scale_csv);
writetable(CostBreakdown_Table, cfg.cost_breakdown_csv);
writetable(MarketScale_Only_Table, cfg.market_only_csv);

%% 6) Save formal result
LFP_MarketScale_Extension_Result = struct();

LFP_MarketScale_Extension_Result.cfg = cfg;
LFP_MarketScale_Extension_Result.input_file = cfg.input_file;

LFP_MarketScale_Extension_Result.scale_ton_list = scale_ton_list;
LFP_MarketScale_Extension_Result.N_list = N_list;
LFP_MarketScale_Extension_Result.k_vals = k_vals;

LFP_MarketScale_Extension_Result.c_pack = c_pack;
LFP_MarketScale_Extension_Result.c_train = c_train;

LFP_MarketScale_Extension_Result.Total_Cost_NK = Total_Cost_NK;
LFP_MarketScale_Extension_Result.O_Cost_NK = O_Cost_NK;
LFP_MarketScale_Extension_Result.A_Cost_NK = A_Cost_NK;
LFP_MarketScale_Extension_Result.R_Cost_NK = R_Cost_NK;
LFP_MarketScale_Extension_Result.Model_Cost_NK = Model_Cost_NK;

LFP_MarketScale_Extension_Result.opt_idx_of_N = opt_idx_of_N;
LFP_MarketScale_Extension_Result.opt_k_of_N = opt_k_of_N;
LFP_MarketScale_Extension_Result.opt_T1_of_N = opt_T1_of_N;
LFP_MarketScale_Extension_Result.opt_T2_of_N = opt_T2_of_N;

LFP_MarketScale_Extension_Result.opt_total_cost_of_N = opt_total_cost_of_N;
LFP_MarketScale_Extension_Result.opt_cost_per_pack_of_N = opt_cost_per_pack_of_N;

LFP_MarketScale_Extension_Result.opt_O_of_N = opt_O_of_N;
LFP_MarketScale_Extension_Result.opt_A_of_N = opt_A_of_N;
LFP_MarketScale_Extension_Result.opt_R_of_N = opt_R_of_N;
LFP_MarketScale_Extension_Result.opt_Model_of_N = opt_Model_of_N;

LFP_MarketScale_Extension_Result.opt_Action_Ratio_of_N = ...
 opt_Action_Ratio_of_N;

LFP_MarketScale_Extension_Result.opt_A1_value_of_N = opt_A1_value_of_N;
LFP_MarketScale_Extension_Result.opt_A2_value_of_N = opt_A2_value_of_N;
LFP_MarketScale_Extension_Result.opt_A3_value_of_N = opt_A3_value_of_N;

LFP_MarketScale_Extension_Result.Gross_executed_action_value_of_N = ...
 Gross_executed_action_value_of_N;

LFP_MarketScale_Extension_Result.Perfect_information_action_value_of_N = ...
 Perfect_information_action_value_of_N;

LFP_MarketScale_Extension_Result.Net_realized_value_of_N = ...
 Net_realized_value_of_N;

% Legacy aliases retained for older table scripts.
LFP_MarketScale_Extension_Result.Total_action_value_of_N = ...
 Gross_executed_action_value_of_N;

LFP_MarketScale_Extension_Result.Net_value_after_cost_of_N = ...
 Net_realized_value_of_N;

LFP_MarketScale_Extension_Result.Net_value_accounting_error_USD = ...
 Net_value_accounting_error_USD;

LFP_MarketScale_Extension_Result.Is_k_on_upper_boundary = ...
 Is_k_on_upper_boundary;

LFP_MarketScale_Extension_Result.MarketScale_Table = MarketScale_Table;
LFP_MarketScale_Extension_Result.CostBreakdown_Table = CostBreakdown_Table;
LFP_MarketScale_Extension_Result.MarketScale_Only_Table = MarketScale_Only_Table;
LFP_MarketScale_Extension_Result.CostBreakdown_Only_Table = ...
 CostBreakdown_Only_Table;

save(cfg.result_mat, ...
 'LFP_MarketScale_Extension_Result', ...
 'MarketScale_Table', ...
 'CostBreakdown_Table', ...
 'MarketScale_Only_Table', ...
 'CostBreakdown_Only_Table', ...
 '-v7.3');

fprintf('\n========== Market-scale extension summary ==========\n');
disp(MarketScale_Table(:, { ...
 'Scale_ton', ...
 'Pack_number', ...
 'Optimal_k', ...
 'Is_k_on_upper_boundary', ...
 'T1_star', ...
 'T2_star', ...
 'Total_recertification_cost_per_pack_USD', ...
 'Gross_executed_action_value_billion_USD', ...
 'Net_realized_value_billion_USD'}));

fprintf('Saved market-scale table: %s\n', cfg.market_scale_csv);
fprintf('Saved cost-breakdown table: %s\n', cfg.cost_breakdown_csv);
fprintf('Saved market-only table: %s\n', cfg.market_only_csv);
fprintf('Saved result MAT: %s\n', cfg.result_mat);
fprintf('================ Part5 Exp07 completed ================\n');
